import type {
  SegmentCompactEmits,
  SegmentCompactProps,
  SegmentCompactSlots,
  SegmentUi,
  SegmentOptionData
} from '@soybeanjs/headless/segment';
import type { AcceptableValue, ClassValue } from '@soybeanjs/headless/types';
import type { TabsFill as SegmentFill, TabsShape as SegmentShape } from '@/styles/tabs';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Segment component.
 */
export interface SegmentProps<T extends SegmentOptionData> extends SegmentCompactProps<T> {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<SegmentUi>;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Shape of the component.
   */
  shape?: SegmentShape;
  /**
   * Fill.
   */
  fill?: SegmentFill;
}

/**
 * Events for the Segment component.
 */
export type SegmentEmits<T extends AcceptableValue = AcceptableValue> = SegmentCompactEmits<T>;

/**
 * Slots for the Segment component.
 */
export type SegmentSlots<T extends SegmentOptionData = SegmentOptionData> = SegmentCompactSlots<T>;

export type { SegmentOptionData, SegmentFill, SegmentShape };

export { default as SSegment } from './segment.vue';

export type * from '@soybeanjs/headless/segment';
export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const tabsVariants = scv({
  slots: {
    root: `flex`,
    list: 'relative inline-flex justify-center items-center bg-muted text-muted-foreground',
    trigger: [
      `relative z-3 inline-flex items-center justify-center flex-1 whitespace-nowrap rounded-md font-medium transition-all-200`,
      `outline-none focus-visible:ring-3  focus-visible:ring-offset-background focus-visible:ring-primary/30`,
      `disabled:cursor-not-allowed disabled:opacity-50`
    ],
    indicator: `absolute top-0 start-0 z-2 transition-[width,height,transform] duration-300`,
    indicatorContent: `w-full h-full bg-background shadow`,
    content: `flex-grow self-stretch transition-all-150 outline-none focus-visible:ring-3  focus-visible:ring-offset-background focus-visible:ring-primary/30`
  },
  variants: {
    size: {
      xs: {
        root: 'text-2xs',
        list: `p-0.75`,
        trigger: `gap-1 px-1.5 py-0.75`
      },
      sm: {
        root: 'text-xs',
        list: `p-0.875`,
        trigger: `gap-1.5 px-2 py-1`
      },
      md: {
        root: 'text-sm',
        list: `p-1`,
        trigger: `gap-2 px-3 py-1`
      },
      lg: {
        root: 'text-base',
        list: `p-1.125`,
        trigger: `gap-2.5 px-4 py-1.125`
      },
      xl: {
        root: 'text-lg',
        list: `p-1.25`,
        trigger: `gap-3 px-5 py-1.25`
      },
      '2xl': {
        root: 'text-xl',
        list: `p-1.5`,
        trigger: `gap-4 px-6 py-1.5`
      }
    },
    orientation: {
      horizontal: {
        root: `flex-col`,
        indicator: `h-full w-[--soybean-tabs-indicator-size] translate-x-[--soybean-tabs-indicator-position] rtl:-translate-x-[--soybean-tabs-indicator-position]`
      },
      vertical: {
        list: `flex-col items-stretch`,
        indicator: `w-full h-[--soybean-tabs-indicator-size] translate-y-[--soybean-tabs-indicator-position]`
      }
    },
    shape: {
      square: {
        list: 'rounded-md',
        indicatorContent: 'rounded-md'
      },
      rounded: {
        list: 'rounded-full',
        indicatorContent: 'rounded-full'
      }
    },
    fill: {
      full: {
        root: `items-stretch`
      },
      auto: {
        root: `items-start`
      }
    },
    enableIndicator: {
      false: {
        trigger: `data-[state=active]:bg-background data-[state=active]:text-foreground data-[state=active]:shadow`
      }
    }
  },
  compoundVariants: [
    {
      size: 'xs',
      orientation: 'horizontal',
      class: {
        indicator: 'py-0.75',
        content: 'mt-1.5'
      }
    },
    {
      size: 'xs',
      orientation: 'vertical',
      class: {
        indicator: 'px-0.75',
        content: 'ms-1.5'
      }
    },
    {
      size: 'sm',
      orientation: 'horizontal',
      class: {
        indicator: 'py-1',
        content: 'mt-1.75'
      }
    },
    {
      size: 'sm',
      orientation: 'vertical',
      class: {
        indicator: 'px-1',
        content: 'ms-1.75'
      }
    },
    {
      size: 'md',
      orientation: 'horizontal',
      class: {
        indicator: 'py-1',
        content: 'mt-2'
      }
    },
    {
      size: 'md',
      orientation: 'vertical',
      class: {
        indicator: 'px-1',
        content: 'ms-2'
      }
    },
    {
      size: 'lg',
      orientation: 'horizontal',
      class: {
        indicator: 'py-1.125',
        content: 'mt-2.5'
      }
    },
    {
      size: 'lg',
      orientation: 'vertical',
      class: {
        indicator: 'px-1.125',
        content: 'ms-2.5'
      }
    },
    {
      size: 'xl',
      orientation: 'horizontal',
      class: {
        indicator: 'py-1.25',
        content: 'mt-3'
      }
    },
    {
      size: 'xl',
      orientation: 'vertical',
      class: {
        indicator: 'px-1.25',
        content: 'ms-3'
      }
    },
    {
      size: '2xl',
      orientation: 'horizontal',
      class: {
        indicator: 'py-1.5',
        content: 'mt-3.5'
      }
    },
    {
      size: '2xl',
      orientation: 'vertical',
      class: {
        indicator: 'px-1.5',
        content: 'ms-3.5'
      }
    }
  ],
  defaultVariants: {
    size: 'md',
    orientation: 'horizontal',
    shape: 'square',
    fill: 'auto',
    enableIndicator: true
  }
});

type TabsProps = VariantProps<typeof tabsVariants>;

export type TabsShape = NonNullable<TabsProps['shape']>;

export type TabsFill = NonNullable<TabsProps['fill']>;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
